let url = $input.first().json.URL;
let clean = url.split('#')[0];
clean = clean.split('?')[0];
if (clean.length > 1 && clean.endsWith('/')) {
  clean = clean.slice(0, -1);
}

return {
  url: clean.trim()
};

let delta = null;
const prevPosition = $input.first().json['position_' + $now.plus({days: -14}).toFormat('yyyy-MM-dd')] || null;
const currentPosition = $('Get live google organic SERP regular').first()?.json?.tasks?.[0]?.result?.[0]?.items?.[0]?.rank_absolute || null;
if (
  prevPosition 
  && prevPosition !== 'Not Found'
  && prevPosition !== 'Error'
  && currentPosition
) {
  delta = prevPosition - currentPosition;
}

let status = 'error';

if ($('Get live google organic SERP regular').first().json.tasks?.[0]?.result?.[0]?.items == null) {
  status = 'not_found';
} else {
  status = 'found';
}

return {
  delta: delta,
  status: status
}

